1092	static void insert_no_dup(struct nonstale_queue *queue, struct commit *c)
1093	{
1094		if (c->object.flags & PARENT2)
1095			return;
1096		nonstale_queue_put(queue, c);
1097		c->object.flags |= PARENT2;
1098	}
